from flask import Flask, render_template, redirect, url_for, render_template_string
from flask_login import LoginManager, UserMixin, login_user, login_required, logout_user, current_user
from flask_wtf import FlaskForm
from wtforms import StringField, PasswordField, SubmitField
from wtforms.validators import DataRequired, Length
from werkzeug.security import generate_password_hash, check_password_hash
import os

class LoginForm(FlaskForm):
    username = StringField('Username', validators=[DataRequired(), Length(min=4, max=25)])
    password = PasswordField('Password', validators=[DataRequired(), Length(min=8, max=80)])
    submit = SubmitField('Log In')

login_manager = LoginManager()

def task_func(secret_key, template_folder):
    app = Flask(__name__, template_folder=template_folder)
    app.config['SECRET_KEY'] = secret_key
    app.config['WTF_CSRF_ENABLED'] = False

    login_manager.init_app(app)
    login_manager.login_view = 'login'

    class User(UserMixin):
        def __init__(self, id, username, password):
            self.id = id
            self.username = username
            self.password_hash = generate_password_hash(password)

        def check_password(self, password):
            return check_password_hash(self.password_hash, password)

    users = {
        'admin': User(1, 'admin', 'password123')
    }

    @login_manager.user_loader
    def load_user(user_id):
        for user in users.values():
            if str(user.id) == str(user_id):
                return user
        return None

    def render_template_safe(template_name, **context):
        """Try to render a template file, fall back to inline template string if not found."""
        template_path = os.path.join(template_folder, template_name)
        if os.path.exists(template_path):
            return render_template(template_name, **context)
        else:
            # Fallback inline templates
            if template_name == 'login.html':
                tmpl = '''<!DOCTYPE html><html><body>
                <form method="POST">
                {{ form.hidden_tag() if form.hidden_tag is defined else "" }}
                {{ form.username.label }} {{ form.username() }}
                {{ form.password.label }} {{ form.password() }}
                {{ form.submit() }}
                </form></body></html>'''
            elif template_name == 'protected.html':
                tmpl = '''<!DOCTYPE html><html><body>
                <p>Logged in as: {{ name }}</p>
                <a href="/logout">Logout</a>
                </body></html>'''
            else:
                tmpl = '''<!DOCTYPE html><html><body>{{ content }}</body></html>'''
            return render_template_string(tmpl, **context)

    @app.route('/login', methods=['GET', 'POST'])
    def login():
        form = LoginForm()
        if form.validate_on_submit():
            username = form.username.data
            password = form.password.data
            user = users.get(username)
            if user and user.check_password(password):
                login_user(user)
                return redirect(url_for('protected'))
        return render_template_safe('login.html', form=form)

    @app.route('/logout')
    @login_required
    def logout():
        logout_user()
        return redirect(url_for('login'))

    @app.route('/protected')
    @login_required
    def protected():
        return render_template_safe('protected.html', name=current_user.username)

    return app

