import subprocess
import psutil
import time
import os

def task_func(script_path: str, timeout=10) -> dict:
    if not os.path.exists(script_path):
        raise FileNotFoundError(f"Script path '{script_path}' does not exist.")

    cpu_usage = 0.0
    memory_usage = 0

    process = subprocess.Popen(['bash', script_path])

    start_time = time.time()

    try:
        ps_process = psutil.Process(process.pid)
        # Initialize cpu_percent to avoid first-call 0.0
        ps_process.cpu_percent(interval=None)

        while True:
            elapsed = time.time() - start_time
            if elapsed >= timeout:
                process.terminate()
                try:
                    process.wait(timeout=2)
                except subprocess.TimeoutExpired:
                    process.kill()
                    process.wait()
                break

            # Check if process has finished
            if process.poll() is not None:
                break

            try:
                status = ps_process.status()
                if status == psutil.STATUS_ZOMBIE:
                    break

                cpu = ps_process.cpu_percent(interval=None)
                mem_info = ps_process.memory_info()

                cpu_usage += cpu
                memory_usage += mem_info.rss

            except (psutil.NoSuchProcess, psutil.ZombieProcess, psutil.AccessDenied):
                break

            time.sleep(0.1)

    except (psutil.NoSuchProcess, psutil.ZombieProcess, psutil.AccessDenied):
        pass
    finally:
        if process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=3)
            except subprocess.TimeoutExpired:
                process.kill()
                process.wait()

    return {
        'CPU Usage': cpu_usage,
        'Memory Usage': memory_usage
    }

