    all_keys = set()
    for record in data:
        all_keys.update(record.keys())

    # Collect numeric values for each key
    key_values = defaultdict(list)

    for record in data:
        for key, value in record.items():
            if isinstance(value, (int, float)) and not isinstance(value, bool):
                key_values[key].append(value)

    # Calculate mean and median for each key (including keys with no numeric values -> NaN)
    results = {}
    for key in all_keys:
        values = key_values[key]
        if values:
            results[key] = {
                'mean': np.mean(values),
                'median': np.median(values)
            }
        else:
            results[key] = {
                'mean': np.nan,
                'median': np.nan
            }

    # Convert to DataFrame, indexed and sorted by variable names
    df = pd.DataFrame.from_dict(results, orient='index', columns=['mean', 'median'])
    df.index.name = None
    df = df.sort_index()

    return df

