from itertools import permutations
import math

def task_func(numbers):
    if not isinstance(numbers, list):
        raise TypeError("numbers must be a list of integers.")
    for n in numbers:
        if not isinstance(n, int):
            raise TypeError("numbers must be a list of integers.")
        if n < 0:
            raise ValueError("Input numbers must be non-negative.")

    if len(numbers) == 0:
        return [], []

    all_perms = list(permutations(numbers))
    factorial_sums = []
    for perm in all_perms:
        total = reduce(lambda acc, x: acc + math.factorial(x), perm, 0)
        factorial_sums.append(total)

    return factorial_sums, all_perms

