import socket
import select
import queue
from datetime import datetime, timedelta

def task_func(
    server_address="localhost", server_port=12345, buffer_size=1024, run_duration=5
):
    # Create the server socket
    server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server.setblocking(False)
    server.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)

    try:
        server.bind((server_address, server_port))
    except OSError:
        # Try a different port if the default is in use
        server.close()
        server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        server.setblocking(False)
        server.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        server.bind((server_address, 0))
        server_port = server.getsockname()[1]

    server.listen(5)

    # Lists for select
    inputs = [server]
    outputs = []
    message_queues = {}

    end_time = datetime.now() + timedelta(seconds=run_duration)

    while True:
        remaining = (end_time - datetime.now()).total_seconds()
        if remaining <= 0:
            break

        try:
            readable, writable, exceptional = select.select(
                inputs, outputs, inputs, min(remaining, 0.1)
            )
        except (select.error, ValueError):
            break

        for s in readable:
            if s is server:
                # Accept new connection
                try:
                    connection, client_address = s.accept()
                    connection.setblocking(False)
                    inputs.append(connection)
                    message_queues[connection] = queue.Queue()
                except Exception:
                    pass
            else:
                # Receive data from client
                try:
                    data = s.recv(buffer_size)
                    if data:
                        # Append current server time to data
                        current_time = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                        response = data + f" {current_time}".encode()
                        message_queues[s].put(response)
                        if s not in outputs:
                            outputs.append(s)
                    else:
                        # Client closed connection
                        if s in outputs:
                            outputs.remove(s)
                        inputs.remove(s)
                        s.close()
                        del message_queues[s]
                except Exception:
                    if s in outputs:
                        outputs.remove(s)
                    if s in inputs:
                        inputs.remove(s)
                    s.close()
                    if s in message_queues:
                        del message_queues[s]

        for s in writable:
            try:
                next_msg = message_queues[s].get_nowait()
            except queue.Empty:
                if s in outputs:
                    outputs.remove(s)
            except KeyError:
                if s in outputs:
                    outputs.remove(s)
            else:
                try:
                    s.send(next_msg)
                except Exception:
                    if s in outputs:
                        outputs.remove(s)
                    if s in inputs:
                        inputs.remove(s)
                    s.close()
                    if s in message_queues:
                        del message_queues[s]

        for s in exceptional:
            if s in inputs:
                inputs.remove(s)
            if s in outputs:
                outputs.remove(s)
            s.close()
            if s in message_queues:
                del message_queues[s]

    # Clean up
    for s in list(inputs):
        try:
            s.close()
        except Exception:
            pass

    return f"Server started on {server_address}:{server_port}, ran for {run_duration} seconds"

