from datetime import datetime
import pytz
import numpy as np

def task_func(time_strings, timezone):
    if len(time_strings) < 2:
        return 0.0

    tz = pytz.timezone(timezone)

    # Try multiple formats to handle different input date formats
    formats = [
        "%Y-%m-%d %H:%M:%S",
        "%d/%m/%y %H:%M:%S.%f",
        "%d/%m/%Y %H:%M:%S.%f",
        "%Y-%m-%d %H:%M:%S.%f",
        "%d/%m/%y %H:%M:%S",
        "%d/%m/%Y %H:%M:%S",
    ]

    def parse_datetime(ts):
        for fmt in formats:
            try:
                return datetime.strptime(ts, fmt)
            except ValueError:
                continue
        raise ValueError(f"Unable to parse time string: {ts}")

    converted_times = []
    for ts in time_strings:
        dt = parse_datetime(ts)
        dt = pytz.utc.localize(dt).astimezone(tz)
        converted_times.append(dt)

    diffs = []
    for i in range(1, len(converted_times)):
        diff = abs((converted_times[i] - converted_times[i-1]).total_seconds())
        diffs.append(diff)

    if not diffs:
        return 0.0

    return float(np.mean(diffs))

